"""
MKT Christ Commentary — Deuteronomy chapters 30–31
Run: python3 scripts/zc-christ-deuteronomy-30-31-fill.py

Note: ch 30 v15 already exists from Phase 2 script — skipped here via merge_comm.

Key decisions:
- Ch 30: v6 (heart circumcision) = the central new covenant promise of Deuteronomy; directly fulfilled in Spirit (Col 2:11-12; Rom 2:29)
- Ch 30: vv.12-14 = direct NT citation in Romans 10:6-8 (Christological reinterpretation)
- Ch 30: v20 ("the LORD is your life") = directly fulfilled in "Christ, who is your life" (Col 3:4)
- Ch 31: v6/v8 = Heb 13:5 direct citation ("never leave nor forsake")
- Ch 31: v7 = Joshua type of Christ leading into rest (Heb 4:8-9)
- Ch 31: v17 = hidden face of God → Christ's cross-desolation (Matt 27:46)
- Ch 31: v19/30 = song of Moses joins song of the Lamb in Rev 15:3-4
- v15 already written — merge_comm will skip it
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUTERONOMY = {
"30": {
"1": "<p>When the blessings and curses have come upon Israel in exile, and they take them to heart — the covenant scenario anticipates the full arc of Israel&apos;s history. In Christ, the full arc is realized: the covenant curses fall on Christ (Gal 3:13), the exile ends through his death that gathers the scattered (John 11:52), and the restoration is enacted. The exile-and-return pattern that Deuteronomy 30 outlines is the macro-structure that Christ&apos;s death and resurrection fulfills at the deepest level. Theme.</p>",
"2": "<p>&quot;When you and your children return to the LORD your God and obey him with all your heart.&quot; The teshuvah — return/repentance — that follows exile. In Christ, the repentance the law commanded becomes the repentance the gospel produces: &quot;Repent and be baptized every one of you in the name of Jesus Christ for the forgiveness of your sins&quot; (Acts 2:38). The full-heart return of Deuteronomy 30 is the NT&apos;s call to conversion, now enabled by the Spirit rather than commanded by law alone. Theme.</p>",
"3": "<p>&quot;The LORD your God will restore your fortunes and have compassion on you, and gather you again from all the nations where he scattered you.&quot; The gathering after the scatter — the exile reversed by divine compassion. Jesus reads this promise in himself: &quot;he would gather into one the children of God who are scattered abroad&quot; (John 11:52). The exile-gathering of Deut 30:3 is what Christ&apos;s death accomplishes — the scattered children of God are brought together through the cross. Direct connection.</p>",
"4": "<p>&quot;Even if you are exiled to the farthest horizon, the LORD your God will gather you from there and bring you back.&quot; The cosmic scope of the promised gathering — no distance exceeds YHWH&apos;s reach. Paul extends this to the eschatological scale: God&apos;s purpose is &quot;to bring all things together under one head, even Christ&quot; (Eph 1:10 — ἀνακεφαλαιώσασθαι, the recapitulation of all things). The gather-from-everywhere of Deuteronomy becomes the gather-all-things-in-Christ of Ephesians. Theme.</p>",
"5": "<p>&quot;The LORD your God will bring you to the land your ancestors possessed, and you will take possession of it. He will make you more prosperous and numerous than your ancestors.&quot; The restoration exceeds the original possession — the return is greater than the first entry. In Christ, the new covenant inheritance exceeds the old: &quot;I came that they may have life and have it abundantly&quot; (John 10:10). The resurrection life surpasses the pre-fall life; the new creation surpasses the first. Revelation of God.</p>",
"6": "<p>&quot;The LORD your God will circumcise your heart and the hearts of your descendants, so that you will love him with all your heart and with all your soul, and so that you may live.&quot; The heart circumcision performed by God himself — what the law commanded (10:16) is here promised as a divine act. This is the pre-echo of the new covenant: Jeremiah 31:33 (law written on the heart), Ezekiel 36:26 (heart of flesh replacing heart of stone). In Christ, the Spirit effects this circumcision: &quot;In him you were also circumcised with a circumcision not performed by human hands... having been buried with him in baptism&quot; (Col 2:11–12); &quot;circumcision of the heart, by the Spirit, not by the letter&quot; (Rom 2:29). The most directly new-covenant verse in Deuteronomy. Direct prophecy fulfilled in Christ through the Spirit.</p>",
"7": "<p>&quot;The LORD your God will inflict all these curses on your enemies and on those who hate and persecute you.&quot; The covenant curse falls on the oppressors rather than on the restored people. In Christ, the covenant curse falls on him who bore it for others (Gal 3:13), and the enemy&apos;s power over God&apos;s people is broken: &quot;He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him&quot; (Col 2:15). The reversal of curse is the structure of redemption. Theme.</p>",
"8": "<p>&quot;You will again obey the LORD and follow all his commands.&quot; The result of heart circumcision (v.6) is genuine obedience — the inner transformation produces the outer response. In Christ, through the Spirit, the righteous requirement of the law is &quot;fulfilled in us, who walk not according to the flesh but according to the Spirit&quot; (Rom 8:4). What the law commanded but could not produce from an uncircumcised heart, the Spirit produces from the circumcised heart. Theme.</p>",
"9": "<p>&quot;The LORD your God will make you most prosperous in all the work of your hands... The LORD will again delight in your well-being, just as he delighted in your ancestors.&quot; The restored delight of YHWH in his people. In Christ, the Father&apos;s delight in the Son is extended to those in him: &quot;he has blessed us in the Beloved&quot; (Eph 1:6 — ἐν τῷ ἠγαπημένῳ, &quot;in the one he loves&quot;). The divine delight that characterized the original covenant and was forfeited through sin is fully restored in Christ. Revelation of God.</p>",
"10": "<p>&quot;If you obey the LORD your God and keep his commands... and if you turn to him with all your heart and with all your soul.&quot; The obedience condition for the covenant blessing. In Christ, this condition is permanently met: he who was perfectly obedient bears the curse of our disobedience and credits his obedience to those in him (Rom 5:19: &quot;through the one man&apos;s obedience the many will be made righteous&quot;). The conditional of Deuteronomy is resolved not by Israel&apos;s perfect obedience but by Christ&apos;s. Theme.</p>",
"11": "<p>&quot;What I am commanding you today is not too difficult for you or beyond your reach.&quot; The law is presented as accessible — the covenant is not an impossible ideal but a livable reality. Paul uses this as the springboard for the Christological reinterpretation in Romans 10:6–8: the word that is near you is not the law that you failed to keep but the word of faith in Christ that is proclaimed. The law&apos;s accessibility prepares for the gospel&apos;s accessibility. Theme.</p>",
"12": "<p>&quot;It is not up in heaven, so that you have to ask, &apos;Who will ascend into heaven to get it?&apos;&quot; Paul quotes this in Romans 10:6 with a Christological reading: &quot;Do not say in your heart, &apos;Who will ascend into heaven?&apos; (that is, to bring Christ down).&quot; There is no need to ascend to heaven to retrieve Christ because he has already descended — the Incarnation is the answer to the rhetorical question. The law&apos;s heaven-inaccessibility argument is re-read as the gospel&apos;s Incarnation announcement. Direct NT citation (Rom 10:6).</p>",
"13": "<p>&quot;Nor is it beyond the sea, so that you have to ask, &apos;Who will cross the sea to get it?&apos;&quot; Paul adapts this in Romans 10:7: &quot;Who will descend into the abyss? (that is, to bring Christ up from the dead).&quot; There is no need to descend to retrieve Christ from death because he has already risen. The sea-crossing impossibility is reread as the resurrection announcement — Christ has already crossed the abyss of death and come back. Direct NT citation (Rom 10:7).</p>",
"14": "<p>&quot;No, the word is very near you; it is in your mouth and in your heart so you may obey it.&quot; Paul quotes this directly in Romans 10:8: &quot;The word is near you, in your mouth and in your heart — that is, the word of faith that we proclaim.&quot; Paul&apos;s entire Christological reinterpretation of Deut 30:12–14 transforms the word of the law into the word of the gospel: the nearness of the covenant word becomes the nearness of Christ. The word in the heart is no longer the Torah commands but Christ himself, who through the Spirit dwells in believers (Eph 3:17: &quot;Christ may dwell in your hearts through faith&quot;). Direct NT citation (Rom 10:8).</p>",
"16": "<p>Love YHWH, walk in his ways, keep his commands → live. The life-path. In Christ, the life-path is fulfilled from within: he who &quot;knew no sin became sin for us, so that in him we might become the righteousness of God&quot; (2 Cor 5:21). The life that covenant obedience was meant to produce is received as a gift in Christ — not earned by keeping the path but received by being united to the one who walked it perfectly. Theme.</p>",
"17": "<p>&quot;But if your heart turns away and you refuse to listen, and if you are drawn away to bow down to other gods.&quot; The covenant warning — the alternative path leads to destruction. The NT&apos;s warning passages (Heb 6:4–6; 10:26–31; 2 Pet 2:20–22) carry the same urgency with heightened stakes: because the revelation in Christ is greater, the danger of turning away is greater. The stakes escalate from Sinai to Calvary. Theme.</p>",
"18": "<p>&quot;I declare to you this day that you will certainly be destroyed.&quot; The covenant curse for apostasy stated with absolute clarity. In Christ, this destruction is averted for those who are in him: &quot;There is therefore now no condemnation for those who are in Christ Jesus&quot; (Rom 8:1). The mōt tāmût (&quot;you will certainly be destroyed&quot;) is what the cross absorbs — Christ becomes the accursed one (Gal 3:13) so that those in him are not destroyed. Direct application.</p>",
"19": "<p>&quot;I have set before you life and death, blessings and curses. Now choose life, so that you and your children may live.&quot; The great covenant call to choose life. In Christ, the choice of life is made possible in a new way — not merely commanded but offered as a person: &quot;I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live&quot; (John 11:25). The life-and-death polarity of Deuteronomy is not abolished but resolved: in Christ, life has conquered death. Theme.</p>",
"20": "<p>&quot;The LORD is your life.&quot; YHWH himself is Israel&apos;s life — not merely the giver of life but its substance and content. This identity is made explicit in the NT: &quot;Christ, who is your life&quot; (Col 3:4); &quot;in him was life, and the life was the light of men&quot; (John 1:4); &quot;I am the resurrection and the life&quot; (John 11:25). The declaration &quot;the LORD is your life&quot; is the OT form of what the NT declares has become fully visible in the Son. Direct connection.</p>"
},
"31": {
"1": "<p>Moses goes and speaks these words to all Israel — the conclusion of the great covenantal address. The faithful mediator completes his charge: every word commissioned to him has been spoken. In Christ: &quot;I have glorified you on earth, having accomplished the work that you gave me to do&quot; (John 17:4); &quot;It is finished&quot; (John 19:30). The pattern of the faithful mediator who completes his commission reaches its ultimate expression in Christ. Theme.</p>",
"2": "<p>&quot;I am a hundred and twenty years old today. I am no longer able to lead you out and bring you in.&quot; Moses reaches his limit. The human mediator — however faithful — is finite. Christ knows no such limit: &quot;he is able to save to the uttermost those who draw near to God through him, since he always lives to make intercession for them&quot; (Heb 7:25). The replacement of the limited Moses by the unlimited Christ is the movement from the old covenant to the new. Theme.</p>",
"3": "<p>&quot;The LORD your God himself will cross over before you... Joshua will lead you across.&quot; YHWH goes first as the divine warrior; Joshua follows as the human instrument. In Christ, the two roles are united: he is both the divine actor (Emmanuel, God with us) and the human representative who crosses through death and resurrection. &quot;He is the pioneer and perfecter of faith&quot; (Heb 12:2) — the forerunner who goes before his people through the ultimate crossing. Theme.</p>",
"4": "<p>YHWH will deal with the Canaanite nations as he dealt with Sihon and Og. Past victories ground future confidence. The resurrection is the past victory that grounds all future confidence for the church: &quot;Since Christ was raised from the dead, he cannot die again; death no longer has mastery over him&quot; (Rom 6:9). The Sihon and Og victories are the type; the resurrection is the antitype from which all Christian confidence flows. Theme.</p>",
"5": "<p>&quot;The LORD will hand them over to you, and you must deal with them according to all the commands I have given you.&quot; Divine initiative and human responsibility operate together. The NT parallel: &quot;work out your own salvation with fear and trembling, for it is God who works in you, both to will and to work for his good pleasure&quot; (Phil 2:12–13). YHWH gives the victory; Israel must act. Christ secures salvation; believers must respond. The two-agency pattern pervades both covenants. Theme.</p>",
"6": "<p>&quot;Be strong and courageous. Do not be afraid or terrified by them — the LORD your God goes with you. He will never leave you or abandon you.&quot; This promise is directly cited in Hebrews 13:5–6: &quot;For he has said, &apos;I will never leave you nor forsake you.&apos; So we can confidently say, &apos;The Lord is my helper; I will not fear.&apos;&quot; The assurance given to Israel before crossing the Jordan becomes the assurance given to every believer in Christ. Direct NT citation (Heb 13:5).</p>",
"7": "<p>Moses commissions Joshua publicly: &quot;Be strong and courageous, for you are the one who will lead this people into the land the LORD swore to give their ancestors.&quot; Joshua commissioned to lead the people into the rest that Moses could not give. Hebrews 4:8–9 makes the Joshua-Christ typology explicit: &quot;if Joshua had given them rest, God would not have spoken of another day later on&quot; — the rest Joshua gave was incomplete, pointing to the Sabbath rest that Christ provides. Direct type (Heb 4:8–9).</p>",
"8": "<p>&quot;The LORD himself goes before you. He will be with you; he will never leave you or abandon you. Do not be afraid or discouraged.&quot; The doubled assurance — to Joshua, then to all Israel. Hebrews 13:5 cites this promise as the ground for the believer&apos;s contentment: God himself has promised permanent presence. Jesus echoes it at the Great Commission: &quot;I am with you always, to the end of the age&quot; (Matt 28:20). The assurance given to the covenant people entering the promised land is the assurance of God&apos;s permanent presence in Christ. Direct NT citation (Heb 13:5; Matt 28:20).</p>",
"9": "<p>Moses writes the law in a book and hands it to the Levitical priests. The written Torah — the externally mediated covenant document. The written law on scroll contrasts with the new covenant&apos;s inward writing: &quot;not written with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts&quot; (2 Cor 3:3). Moses writes the law; the Spirit writes the law on the heart. The scroll is the shadow; the Spirit-written heart is the fulfillment. Shadow.</p>",
"10": "<p>Every seventh year at the Feast of Booths, read the law publicly. The public covenant renewal reading during the sabbatical year — the time of debt release combined with the festival of joy. Both the debt-release and the joy-festival are fulfilled in Christ: the debt canceled at the cross (Col 2:13–14), the feast of joy in the Lord&apos;s presence. The Deuteronomic public reading is the prototype of the church&apos;s Scripture reading: &quot;Devote yourself to the public reading of Scripture&quot; (1 Tim 4:13). Theme.</p>",
"11": "<p>&quot;When all Israel comes to appear before the LORD your God at the place he chooses, you must read this law aloud before all Israel in their hearing.&quot; The comprehensive public hearing — the entire assembly must hear the covenant word. In the new covenant assembly, the word of God is central: &quot;Let the word of Christ dwell in you richly, teaching and admonishing one another in all wisdom&quot; (Col 3:16). The Deuteronomic public hearing is the template for the church&apos;s life under the word. Theme.</p>",
"12": "<p>&quot;Gather the entire people — men, women, children, and the foreigners living in your towns — so they can hear, learn to fear the LORD your God.&quot; The comprehensive assembly includes men, women, children, and foreigners. In Christ, the comprehensive assembly is extended to every tribe, tongue, and nation: &quot;you are all one in Christ Jesus&quot; (Gal 3:28). The all-inclusive assembly that Moses commands becomes the all-inclusive body of Christ. Theme.</p>",
"13": "<p>&quot;The children who do not yet know the law must hear it and learn to fear the LORD your God throughout all the time you live in the land.&quot; Intergenerational transmission — covenant knowledge must pass to each new generation. The NT carries this responsibility forward: &quot;bring them up in the discipline and instruction of the Lord&quot; (Eph 6:4). In Christ, the transmission is not only of a written code but of a living relationship — &quot;what we have heard... we proclaim also to you, so that you too may have fellowship with us; and indeed our fellowship is with the Father and with his Son Jesus Christ&quot; (1 John 1:1–3). Theme.</p>",
"14": "<p>&quot;The time of your death is drawing near.&quot; YHWH tells Moses his death is near. Moses approaches the divine presence for the final commissioning before his death. The mediator who must die and be succeeded: &quot;the former priests were many in number, because they were prevented by death from continuing in office, but he holds his priesthood permanently, because he continues forever&quot; (Heb 7:23–24). Moses&apos; death marks the limit of the old covenant mediator; Christ&apos;s indestructible life marks the limitlessness of the new. Direct type (Heb 7).</p>",
"15": "<p>YHWH appears at the tent in a pillar of cloud. The theophanic cloud — YHWH&apos;s presence in visible, non-image form. The cloud of divine presence recurs at the Transfiguration (Matt 17:5: &quot;a bright cloud overshadowed them&quot;), the ascension (Acts 1:9: &quot;he was taken up... a cloud took him out of their sight&quot;), and the return (Rev 1:7: &quot;he is coming with clouds&quot;). The cloud is the consistent marker of divine presence whose final appearance is the return of Christ. Theme.</p>",
"16": "<p>YHWH warns: after Moses&apos; death, Israel will chase foreign gods and break the covenant. The divine foreknowledge of Israel&apos;s apostasy. The foreknown failure is the occasion for the promised remedy: Jeremiah 31:31–34 — &quot;Not like the covenant I made with their fathers... my covenant that they broke... I will make a new covenant.&quot; The predicted covenant-breaking of Deut 31:16 is the negative space that the new covenant fills. In Christ, the new covenant that addresses this failure is enacted: &quot;This cup is the new covenant in my blood&quot; (Luke 22:20). Theme.</p>",
"17": "<p>&quot;My anger will blaze against them that day, and I will abandon them and hide my face from them.&quot; The hiding of the divine face (hester panim) — the withdrawal of God&apos;s favorable presence — is the deepest dimension of covenant curse. Christ experiences this desolation at the cross: &quot;My God, my God, why have you forsaken me?&quot; (Matt 27:46, citing Ps 22:1). The hidden face of God that Israel would experience in exile, Christ experienced in abandonment at Calvary — absorbing the covenant curse so that those in him need not face permanent divine abandonment. Shadow fulfilled in Christ&apos;s cross-desolation.</p>",
"18": "<p>&quot;I will certainly conceal my face that day because of all the evil they have done — they have turned to other gods.&quot; The concealed face of God as the consequence of idolatry. In Christ, the concealed face becomes the revealed face: &quot;the light of the knowledge of God&apos;s glory displayed in the face of Christ&quot; (2 Cor 4:6). The face hidden in divine wrath is unveiled in the Son. What was turned away from the covenant-breaker is turned toward those in Christ. Direct contrast and fulfillment.</p>",
"19": "<p>&quot;Now write down this song and teach it to the Israelites... so that this song will serve as a witness for me against them.&quot; The song of Moses — the great covenant witness-poem of chapter 32. In Revelation 15:3–4, the redeemed standing before the throne sing &quot;the song of Moses, the servant of God, and the song of the Lamb,&quot; praising YHWH for his justice and holiness. The song that testified against covenant-breaking Israel becomes, in the new creation, the song of the redeemed who have been freed from the covenant curse by the Lamb. Direct NT connection (Rev 15:3–4).</p>",
"20": "<p>YHWH predicts: when they prosper in the land of milk and honey, they will turn to other gods and break the covenant. The pattern of prosperity-leading-to-apostasy is predicted before it happens — the entire subsequent history of Israel is anticipated here. The new covenant addresses the root cause: &quot;I will put my law within them, and I will write it on their hearts&quot; (Jer 31:33). What Deuteronomy 31:20 predicts as inevitable apostasy, Jeremiah 31:33 promises to cure through the inner transformation that Christ enacts through the Spirit. Theme.</p>",
"21": "<p>&quot;I know what they are already planning to do, even now, before they have entered the land I promised.&quot; YHWH&apos;s omniscient foreknowledge of human rebellion — even before the first step into the land, the failure is known. The same omniscient God who foreknew Israel&apos;s rebellion also elected before the foundation of the world: &quot;he chose us in him before the foundation of the world&quot; (Eph 1:4). Divine foreknowledge of both failure and grace coexist in the same sovereign God. Revelation of God.</p>",
"22": "<p>Moses writes down the song that very day — immediate obedience to YHWH&apos;s command. The faithful servant does what the master commands on the day it is commanded. In Christ, the perfect obedience extends to every command of the Father: &quot;I always do the things that are pleasing to him&quot; (John 8:29); &quot;I have glorified you on earth, having accomplished the work that you gave me to do&quot; (John 17:4). Revelation of God.</p>",
"23": "<p>&quot;Be strong and courageous, for you will bring the Israelites into the land I swore to give them. I will be with you.&quot; YHWH&apos;s direct commissioning of Joshua with the assurance of divine presence. The &quot;I will be with you&quot; formula runs through the OT (Gen 26:24; 28:15; Exod 3:12; Josh 1:5) and reaches its ultimate expression in the Incarnation: &quot;Emmanuel, which means God with us&quot; (Matt 1:23). The assurance given to every covenant servant finds its permanent form in the Son who is himself &quot;God with us.&quot; Theme.</p>",
"24": "<p>Moses finishes writing the entire law in a book. The completion of the written Torah — Moses&apos; literary commission fulfilled. The written Torah is complete. Christ&apos;s completion of his redemptive mission echoes this: &quot;It is finished&quot; (John 19:30 — τετέλεσται, the perfect tense of completion). What Moses finished was a covenant document; what Christ finished was the redemption the document pointed toward. Type.</p>",
"25": "<p>Moses gives the command to the Levites who carried the ark. The Levites as the carriers of the covenant — their ministry is the physical preservation and transport of YHWH&apos;s dwelling and law. In Christ, the church carries a greater testimony: &quot;we are ambassadors for Christ, God making his appeal through us&quot; (2 Cor 5:20). The covenant-carriers of the old covenant are the type of the gospel-bearers of the new. Theme.</p>",
"26": "<p>&quot;Take this scroll of the law and place it beside the ark of the covenant of the LORD your God. It will remain there as a witness against you.&quot; The book placed beside the ark as a witness against covenant violation — the Torah testifies against the lawbreaker. In Christ, the accusatory testimony is replaced by the advocating intercession: &quot;he always lives to make intercession for them&quot; (Heb 7:25). The Torah that witnesses against becomes, through Christ, the covenant that witnesses for. Shadow/contrast.</p>",
"27": "<p>&quot;I know how rebellious and stubborn you are. Even today, while I am still with you, you have been defiant toward the LORD.&quot; Moses&apos; honest final assessment: the problem is not lack of instruction but incorrigible stubbornness. This is the OT&apos;s most direct statement that the human heart&apos;s resistance to God is congenital and persistent. The gospel addresses the same assessment: not by better law but by new birth — &quot;you must be born again&quot; (John 3:7) — and by the Spirit who transforms the stubborn heart from within (Ezek 36:26–27). Revelation of God leading to new covenant promise.</p>",
"28": "<p>&quot;Gather all the elders... so I can speak these words in their hearing and call heaven and earth to testify against them.&quot; The cosmic covenant lawsuit assembled before Moses&apos; death. Heaven and earth as witnesses to the covenant. In Revelation, the cosmic court is assembled before the throne of Christ for the final judgment (Rev 20:11–15). The Deuteronomic lawsuit-witnesses are the type of the eschatological judgment court. Shadow.</p>",
"29": "<p>&quot;I know that after my death you will become deeply corrupt and turn away from everything I have commanded. Disaster will come upon you in the days ahead.&quot; Moses predicts the post-exodus apostasy that Israel&apos;s entire subsequent history fulfilled — from Judges through the exile. In Christ, the cycle of apostasy that Moses predicts is broken not by human resolve but by the Spirit who writes the law on the heart (Jer 31:33; Ezek 36:26). The prediction of failure is the negative space that makes the new covenant&apos;s promise of transformation necessary and credible. Theme.</p>",
"30": "<p>Moses recites the words of this song in the hearing of the entire assembly — the great covenant witness-poem (ch. 32) proclaimed publicly to all Israel. The covenant community hears the words that will testify against them. In Revelation 15:3–4, the redeemed sing this song before the throne: &quot;They sang the song of Moses, the servant of God, and the song of the Lamb.&quot; What was sung as a covenant lawsuit against Israel becomes, in the eschatological assembly, the song of the redeemed. The trajectory from accusatory witness to redemptive praise is the arc of the whole Bible. Direct NT connection (Rev 15:3–4).</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'deuteronomy')
    merge_comm(existing, DEUTERONOMY)
    save_comm('mkt-christ', 'deuteronomy', existing)
    print('Deuteronomy 30-31 mkt-christ written.')

if __name__ == '__main__':
    main()
